const wh = $input.first().json.body;

const userMessage = `Write a knowledge base article for the **${wh.suggested_department}** department that answers:

> ${wh.query}

Additional context from the requester: ${wh.message || 'No additional details provided.'}

Make sure the article would help future employees who search for similar questions.`;

const apiKey = wh.api_key || 'YOUR_DEEPSEEK_API_KEY';

const deepseekResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.deepseek.com/chat/completions',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
  },
  body: {
    model: 'deepseek-chat',
    messages: [
      {
        role: 'system',
        content: 'You are a technical documentation writer for TechCorp. Write a comprehensive, well-structured knowledge base article in markdown. Include: a clear H1 title, ## sections for Overview / Key Points / Detailed Information / Related Resources, bullet points for quick scanning, and actionable takeaways. Be thorough but concise. Write ONLY the markdown article — no preamble, no meta-commentary.',
      },
      {
        role: 'user',
        content: userMessage,
      },
    ],
    temperature: 0.2,
    max_tokens: 2000,
  },
  json: true,
});

let draftContent = '';
try {
  draftContent = deepseekResp.choices[0].message.content;
} catch (e) {
  draftContent = `# ${wh.query}

> ⚠️ Auto-generated fallback for **${wh.suggested_department}** department.

*DeepSeek did not return content. Please review manually.*`;
}

return {
  id: wh.id,
  draft_content: draftContent,
};
